SELECT COUNT(DISTINCT LPB.PK) AS QUANTIDADE FROM LATTES_P_PRODBIB LPP JOIN LATTES_PRODBIB LPB ON LPB.PK = LPP.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE WHERE S.SIGLA_CAMPUS = 'LIN' AND LOWER(COALESCE(S.AREA_INGRESSO, S.AREA_INGRESSO_OG, '')) LIKE '%enfermagem%' AND LPB.ANO GLOB '[0-9][0-9][0-9][0-9]' AND CAST(LPB.ANO AS INTEGER) = 2021 AND LOWER(COALESCE(LPB.TIPO, '')) LIKE '%resumo%' AND LOWER(COALESCE(LPB.TIPO, '')) LIKE '%trabalho%'